1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 2 neighbors survives (rule 2 - survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("live cell with 3 neighbors survives (rule 2 - survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
20	    expect(result).toContainEqual([0, 0]);
21	  });
22	  it("live cell with 4 neighbors dies (rule 3 - overpopulation)", () => {
23	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("dead cell with exactly 3 neighbors becomes alive (rule 4 - reproduction) — [(0,0),(1,0),(0,1)] produces (1,1)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
31	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
32	    const result = nextGeneration(block);
33	    expect(result.sort()).toEqual(block.sort());
34	  });
35	  it("blinker vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
36	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
37	    const sortKey = (c: Cell) => `${c[0]},${c[1]}`;
38	    expect(result.sort((a, b) => sortKey(a).localeCompare(sortKey(b))))
39	      .toEqual([[-1, 1], [0, 1], [1, 1]].sort((a, b) => sortKey(a as Cell).localeCompare(sortKey(b as Cell))));
40	  });
41	  it.todo("handles negative coordinates correctly");
42	});
